def normalize_projection(proj: Dict[str, Any]) -> Dict[str, Any]:
    if not proj:
        return {}
    out: Dict[str, Any] = {}
    for k, v in proj.items():
        if not isinstance(k, str) or not k:
            raise ValidationError("Projection keys must be non-empty strings")
