def build_where(expr: str) -> Any:
    e = expr.strip()
    if e.startswith("function"):
        return e
    if e.startswith("(") and "function" in e[:30]:
        return e
    if e.startswith("{") and "return" in e:
        return "function(){ " + e.strip("{} \n\r\t") + " }"
    return f"function(){{ return ({e}); }}"


def get_collection(mongo_uri: str, ns: str) -> Collection:
    db_name, coll_name = parse_namespace(ns)
    client = MongoClient(mongo_uri, serverSelectionTimeoutMS=10000)
    return client[db_name][coll_name]


